import React, { useState } from 'react';
import { useAppStore } from '../services/store';
import { User, Role } from '../types';
import { Shield, BookOpen, Calculator, UserCheck, Lock, Mail, User as UserIcon, TestTube, Check, Upload, FileSpreadsheet, Download, Table, X, HelpCircle } from 'lucide-react';
import { createUserWithEmailAndPassword, signInWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';
import { auth } from '../services/firebase';

const Auth: React.FC = () => {
  const { state, dispatch } = useAppStore();
  const [isLogin, setIsLogin] = useState(true);

  // Login State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  // Register State
  const [isBulk, setIsBulk] = useState(false);
  const [regForm, setRegForm] = useState<Partial<User>>({
    name: '', email: '', role: 'student', phone: '', address: '',
    classId: '', section: '', annualFee: 0, discount: 0, subjects: [], password: ''
  });
  const [regSuccess, setRegSuccess] = useState('');
  const [bulkFile, setBulkFile] = useState<File | null>(null);
  const [bulkPreview, setBulkPreview] = useState<User[]>([]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setStatusMessage('');

    try {
        await signInWithEmailAndPassword(auth, email, password);
        const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());

        if (user) {
            if (user.status !== 'active' && user.role !== 'developer') {
                setError('Your account is pending approval by an administrator.');
                return;
            }
            dispatch({ type: 'LOGIN', payload: user });
        } else {
            setError('User profile not found in database.');
        }
    } catch (firebaseError: any) {
        const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());
        if (user && user.password === password) {
            if (user.status !== 'active') {
                setError('Your account is pending approval by an administrator.');
                return;
            }
            dispatch({ type: 'LOGIN', payload: user });
        } else {
            setError(firebaseError.code === 'auth/invalid-credential' ? 'Invalid credentials' : 'Login failed: ' + firebaseError.message);
        }
    }
  };

  const handleForgotPassword = async () => {
      if (!email) {
          setError('Please enter your email address first.');
          return;
      }
      setError('');
      try {
          await sendPasswordResetEmail(auth, email);
          setStatusMessage('Password reset link sent! Check your inbox.');
      } catch (err: any) {
          setError('Failed to send reset email: ' + err.message);
      }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!regForm.password || regForm.password.length < 6) {
        setError('Password must be at least 6 characters long.');
        return;
    }

    const isDev = regForm.role === 'developer';

    try {
        const userCredential = await createUserWithEmailAndPassword(auth, regForm.email!, regForm.password);
        const uid = userCredential.user.uid;

        const newUser: User = {
            id: uid,
            name: regForm.name || '',
            email: regForm.email || '',
            role: regForm.role as Role,
            allowedRoles: [regForm.role as Role],
            password: 'password',
            status: isDev ? 'active' : 'pending',
            phone: regForm.phone,
            address: regForm.address,
            annualFee: 0, 
            discount: 0,
            totalPaid: 0,
            ...(regForm.role === 'student' && regForm.classId ? { classId: regForm.classId } : {}),
            ...(regForm.role === 'student' && regForm.section ? { section: regForm.section } : {}),
            ...(regForm.role === 'teacher' && regForm.subjects ? { subjects: regForm.subjects } : {})
        };

        dispatch({ type: 'ADD_USER', payload: newUser });
        setRegSuccess(isDev ? 'Developer Account Created!' : 'Registration submitted. Please wait for approval.');
        setRegForm({ name: '', email: '', role: 'student', phone: '', address: '', classId: '', section: '', annualFee: 0, discount: 0, subjects: [], password: '' });

        setTimeout(() => {
            setRegSuccess('');
            setIsLogin(true);
        }, 3000);
    } catch (err: any) {
        if (err.code === 'auth/email-already-in-use') {
            setError('This email is already registered.');
        } else {
            setError(err.message || 'Registration failed.');
        }
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      if (!regForm.classId) {
          setError("Please select a target Class before uploading.");
          e.target.value = '';
          return;
      }
      setError('');
      setBulkFile(file);
      const reader = new FileReader();
      reader.onload = async (event) => {
          const text = event.target?.result as string;
          if (!text) return;
          const rows = text.split(/\r?\n/).filter(row => row.trim().length > 0);
          const firstRowLower = rows[0].toLowerCase();
          const startIndex = (firstRowLower.includes('email') || firstRowLower.includes('name')) ? 1 : 0;
          const parsedUsers: User[] = [];
          for (let i = startIndex; i < rows.length; i++) {
              const cols = rows[i].split(',').map(c => c.trim());
              let name = '', emailRaw = '', password = '';
              if (cols.length >= 4) {
                  name = cols[1]; emailRaw = cols[2]; password = cols[3];
              } else if (cols.length === 3) {
                  name = cols[0]; emailRaw = cols[1]; password = cols[2];
              } else continue;
              if (name && emailRaw) {
                  let email = emailRaw;
                  if (!email.includes('@')) email = `${email}@galaxy.edu.np`;
                  parsedUsers.push({
                      id: `bulk_${Date.now()}_${i}`,
                      name, email, password: password || 'password',
                      role: 'student', allowedRoles: ['student'], status: 'pending',
                      classId: regForm.classId, section: regForm.section || '',
                      annualFee: 0, discount: 0, totalPaid: 0
                  } as User);
              }
          }
          if (parsedUsers.length === 0) {
              setError("No valid student data found in CSV.");
              setBulkFile(null);
          } else setBulkPreview(parsedUsers);
      };
      reader.readAsText(file);
  };

  const confirmBulkUpload = () => {
      bulkPreview.forEach(u => dispatch({ type: 'ADD_USER', payload: u }));
      setRegSuccess(`Successfully processed ${bulkPreview.length} students.`);
      setBulkPreview([]);
      setBulkFile(null);
      setTimeout(() => { setRegSuccess(''); setIsLogin(true); }, 4000);
  };

  const selectedClassData = state.systemClasses.find(c => c.name === regForm.classId);

  return (
    <div className="min-h-screen bg-gradient-to-br from-galaxy-900 via-galaxy-800 to-galaxy-600 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-4xl w-full flex flex-col md:flex-row gap-8">
        <div className="md:w-1/3 flex flex-col justify-center border-r border-gray-100 pr-8">
            <div className="w-16 h-16 bg-gold-400 rounded-xl flex items-center justify-center text-galaxy-900 font-bold text-3xl mb-6">G</div>
            <h1 className="text-3xl font-bold text-galaxy-900 mb-2">Galaxy Hotel</h1>
            <h2 className="text-xl font-medium text-galaxy-600 mb-6">& Tourism School</h2>
            <p className="text-gray-500 text-sm leading-relaxed">Access the portal to manage your academic and financial records.</p>
        </div>

        <div className="md:w-2/3">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold text-gray-800">{isLogin ? 'Sign In' : 'Create Account'}</h3>
                <button 
                    onClick={() => { setIsLogin(!isLogin); setError(''); setStatusMessage(''); setIsBulk(false); }}
                    className="text-right flex flex-col items-end group"
                >
                    <span className="text-xs text-gray-500 font-medium">{isLogin ? 'Need an account?' : 'Have an account?'}</span>
                    <span className="text-2xl font-extrabold text-galaxy-600 group-hover:underline">{isLogin ? 'Sign Up' : 'Sign In'}</span>
                </button>
            </div>

            {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm flex items-center gap-2"><X size={16}/> {error}</div>}
            {statusMessage && <div className="bg-green-50 text-green-600 p-3 rounded mb-4 text-sm flex items-center gap-2"><Check size={16}/> {statusMessage}</div>}
            {regSuccess && <div className="bg-green-50 text-green-600 p-3 rounded mb-4 text-sm">{regSuccess}</div>}

            {isLogin ? (
                <>
                <form onSubmit={handleLogin} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
                        <div className="relative">
                            <Mail className="absolute left-3 top-2.5 text-gray-400" size={18} />
                            <input 
                                type="email" 
                                className="w-full border pl-10 p-2 rounded-lg focus:ring-2 focus:ring-galaxy-500 outline-none"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                placeholder="name@galaxy.edu.np"
                                required
                            />
                        </div>
                    </div>
                    <div>
                        <div className="flex justify-between mb-1">
                            <label className="block text-sm font-medium text-gray-700">Password</label>
                            <button 
                                type="button" 
                                onClick={handleForgotPassword}
                                className="text-xs text-galaxy-600 hover:text-galaxy-800 flex items-center gap-1"
                            >
                                <HelpCircle size={12}/> Forgot Password?
                            </button>
                        </div>
                        <div className="relative">
                            <Lock className="absolute left-3 top-2.5 text-gray-400" size={18} />
                            <input 
                                type="password" 
                                className="w-full border pl-10 p-2 rounded-lg focus:ring-2 focus:ring-galaxy-500 outline-none"
                                value={password}
                                onChange={e => setPassword(e.target.value)}
                                placeholder="••••••••"
                                required
                            />
                        </div>
                    </div>
                    <button type="submit" className="w-full bg-galaxy-900 text-white py-3 rounded-lg hover:bg-galaxy-800 font-bold shadow-lg transform transition active:scale-95">
                        Login to Portal
                    </button>
                </form>

                {email === 'opentesting' && (
                    <div className="mt-8 pt-6 border-t border-gray-100 animate-in fade-in">
                        <label className="block text-xs font-bold text-red-500 uppercase mb-2 flex items-center gap-1"><TestTube size={14} /> Quick Access</label>
                        <select
                            className="w-full text-sm border border-red-200 bg-red-50 text-red-800 rounded-lg p-2.5"
                            onChange={(e) => {
                                const user = state.users.find(u => u.email === e.target.value);
                                if(user) dispatch({ type: 'LOGIN', payload: user });
                            }}
                            defaultValue=""
                        >
                            <option value="" disabled>-- Quick Login As --</option>
                            <option value="admin@galaxy.edu.np">Super Admin</option>
                            <option value="ramesh@galaxy.edu.np">Accountant</option>
                            <option value="sarita@galaxy.edu.np">Teacher</option>
                            <option value="dheejan@gmail.com">Developer</option>
                        </select>
                    </div>
                )}
                </>
            ) : (
                <div className="space-y-4">
                    <div className="flex bg-gray-100 p-1 rounded-lg mb-4">
                        <button type="button" onClick={() => setIsBulk(false)} className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${!isBulk ? 'bg-white shadow-sm text-galaxy-900' : 'text-gray-500'}`}>Individual</button>
                        <button type="button" onClick={() => setIsBulk(true)} className={`flex-1 py-2 text-sm font-medium rounded-md transition-all flex items-center justify-center gap-2 ${isBulk ? 'bg-white shadow-sm text-galaxy-900' : 'text-gray-500'}`}><FileSpreadsheet size={16}/> Bulk</button>
                    </div>

                    {!isBulk ? (
                        <form onSubmit={handleRegister} className="space-y-3 h-[350px] overflow-y-auto pr-2 custom-scrollbar">
                             <div>
                                <label className="block text-sm font-medium text-gray-700">Account Type</label>
                                <select className="w-full border p-2 rounded mt-1 bg-gray-50" value={regForm.role} onChange={e => setRegForm({...regForm, role: e.target.value as Role})} required>
                                    <option value="student">Student</option>
                                    <option value="teacher">Teacher</option>
                                    <option value="accountant">Accountant</option>
                                    <option value="admin">Admin</option>
                                </select>
                            </div>
                            <div className="grid grid-cols-2 gap-3">
                                <div><label className="text-sm font-medium text-gray-700">Full Name</label><input type="text" required className="w-full border p-2 rounded mt-1" value={regForm.name} onChange={e => setRegForm({...regForm, name: e.target.value})}/></div>
                                <div><label className="text-sm font-medium text-gray-700">Email</label><input type="email" required className="w-full border p-2 rounded mt-1" value={regForm.email} onChange={e => setRegForm({...regForm, email: e.target.value})}/></div>
                            </div>
                            <div className="grid grid-cols-2 gap-3">
                                <div><label className="text-sm font-medium text-gray-700">Phone</label><input type="text" className="w-full border p-2 rounded mt-1" value={regForm.phone} onChange={e => setRegForm({...regForm, phone: e.target.value})}/></div>
                                <div><label className="text-sm font-medium text-gray-700">Password</label><input type="password" required className="w-full border p-2 rounded mt-1" value={regForm.password} onChange={e => setRegForm({...regForm, password: e.target.value})} minLength={6}/></div>
                            </div>
                            <button type="submit" className="w-full bg-galaxy-600 text-white py-2 rounded-lg hover:bg-galaxy-700 font-semibold mt-4">Register Account</button>
                        </form>
                    ) : (
                        <div className="space-y-4 h-[350px] overflow-y-auto pr-2 flex flex-col">
                            {bulkPreview.length === 0 ? (
                                <>
                                    <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg text-sm text-blue-800">
                                        <h4 className="font-bold flex items-center gap-2 mb-2"><Upload size={16}/> Bulk Registration</h4>
                                        <p>Upload a CSV with Name, Email, and Password columns.</p>
                                    </div>
                                    <div className="mt-2">
                                        <label className="block text-xs font-medium text-gray-700 uppercase">Target Class</label>
                                        <select className="w-full border p-2 rounded mt-1 text-sm bg-white" value={regForm.classId} onChange={e => setRegForm({...regForm, classId: e.target.value})}>
                                            <option value="">-- Select Class --</option>
                                            {state.systemClasses.map(cls => <option key={cls.name} value={cls.name}>{cls.name}</option>)}
                                        </select>
                                    </div>
                                    <div className="mt-4 border-2 border-dashed border-gray-300 rounded-lg p-6 flex flex-col items-center bg-gray-50">
                                        <input type="file" accept=".csv" onChange={handleFileUpload} className="hidden" id="csvUpload"/>
                                        <label htmlFor="csvUpload" className="cursor-pointer flex flex-col items-center"><Upload className="text-gray-400 mb-2" size={32} /><span className="text-sm text-gray-600">Select CSV</span></label>
                                    </div>
                                </>
                            ) : (
                                <div className="flex-1 flex flex-col">
                                    <h4 className="font-bold mb-2 flex items-center gap-2"><Table size={16} /> Preview ({bulkPreview.length})</h4>
                                    <div className="flex-1 overflow-auto border rounded-lg bg-gray-50"><table className="w-full text-xs"><thead><tr className="bg-gray-200"><th>Name</th><th>Email</th></tr></thead><tbody>{bulkPreview.map((u, i) => <tr key={i} className="bg-white"><td>{u.name}</td><td>{u.email}</td></tr>)}</tbody></table></div>
                                    <button onClick={confirmBulkUpload} className="w-full bg-green-600 text-white py-3 rounded-lg mt-4 font-bold flex items-center justify-center gap-2"><Check size={18} /> Confirm Upload</button>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState } from 'react';
import { useAppStore } from '../../services/store';
import { Role, User, ExamType, SubjectType, Notice } from '../../types';
import AccountantView from './AccountantView';
import { Check, X, Printer, Lock, Unlock, AlertTriangle, RefreshCw, UserCheck, Shield, BookOpen, Edit2, Search, Filter, Eye, Settings, Plus, Trash2, Calendar, Layout, ChevronRight, ChevronDown, UploadCloud, Database, ScanFace, LogIn, Briefcase, GraduationCap, Calculator, ChevronLeft, Bell, Send, Users, Clock, Key } from 'lucide-react';
import { INITIAL_STATE } from '../../services/mockData';

interface Props {
  activeTab: string;
  role: Role;
}

const AdminView: React.FC<Props> = ({ activeTab, role }) => {
  const { state, dispatch } = useAppStore();
  const { currentUser } = state;

  // Notice Form
  const [noticeForm, setNoticeForm] = useState({ title: '', content: '', audience: 'all' as 'all' | 'students' | 'teachers' });

  // Search and Filter State
  const [searchTerm, setSearchTerm] = useState('');
  const [filterRole, setFilterRole] = useState<string>('all');

  // Impersonation State
  const [viewMode, setViewMode] = useState<'roles' | 'users'>('roles');
  const [selectedRoleForImp, setSelectedRoleForImp] = useState<Role | null>(null);
  const [impSearch, setImpSearch] = useState('');

  // Approval / Edit Modal State
  const [reviewUser, setReviewUser] = useState<User | null>(null);
  const [reviewData, setReviewData] = useState<Partial<User>>({});

  // System Management State
  const [showSubjectManager, setShowSubjectManager] = useState(false);
  const [newSubject, setNewSubject] = useState('');
  const [newSubjectType, setNewSubjectType] = useState<SubjectType>('Theory');

  const [showClassManager, setShowClassManager] = useState(false);
  const [newClass, setNewClass] = useState('');
  const [newSection, setNewSection] = useState('');
  const [activeClassForSection, setActiveClassForSection] = useState<string | null>(null);

  // Exam Session Form
  const [newSessionName, setNewSessionName] = useState('');
  const [newSessionType, setNewSessionType] = useState<ExamType>('Term Exam');
  const [publishClassId, setPublishClassId] = useState('');
  const [publishSection, setPublishSection] = useState('');

  // Hierarchy Definition
  const roleHierarchy: Record<string, number> = {
    developer: 100,
    admin: 90,
    accountant: 50,
    teacher: 50,
    student: 10,
    intern: 10,
    guest: 0
  };

  const handlePostNotice = (e: React.FormEvent) => {
      e.preventDefault();
      if (!noticeForm.title || !noticeForm.content) return;

      const newNotice: Notice = {
          id: `n${Date.now()}`,
          title: noticeForm.title,
          content: noticeForm.content,
          audience: noticeForm.audience,
          date: new Date().toISOString().split('T')[0],
          postedBy: currentUser?.name || 'Administrator'
      };

      dispatch({ type: 'ADD_NOTICE', payload: newNotice });
      setNoticeForm({ title: '', content: '', audience: 'all' });
      alert('Notice published successfully.');
  };

  const getPendingUsers = () => {
      return state.users.filter(u => u.status === 'pending').filter(u => {
          if (role === 'developer') return u.role === 'admin';
          if (role === 'admin') return u.role !== 'developer';
          return false;
      });
  };

  const openReviewModal = (user: User) => {
      setReviewUser(user);
      setReviewData({ ...user, allowedRoles: user.allowedRoles || [user.role] });
  };

  const confirmApprovalOrEdit = () => {
      if (!reviewUser) return;
      const updates: Partial<User> = { ...reviewData };
      delete updates.status; 

      if (updates.role === 'student') {
          updates.annualFee = Number(updates.annualFee || 0);
          updates.discount = Number(updates.discount || 0);
      }

      if (updates.allowedRoles && updates.role && !updates.allowedRoles.includes(updates.role)) {
          updates.allowedRoles.push(updates.role);
      }

      if (reviewUser.status === 'pending') {
          dispatch({ type: 'APPROVE_USER', payload: { id: reviewUser.id, updates } });
      } else {
          dispatch({ type: 'UPDATE_USER_DETAILS', payload: { id: reviewUser.id, ...updates } });
      }
      setReviewUser(null);
      setReviewData({});
  };

  const handleReject = (id: string) => {
      if(window.confirm('Reject this registration?')) {
          dispatch({ type: 'REJECT_USER', payload: id });
      }
  };

  const handleAddSubject = () => {
      if(newSubject.trim()) {
          dispatch({ type: 'ADD_SYSTEM_SUBJECT', payload: { name: newSubject.trim(), type: newSubjectType } });
          setNewSubject('');
      }
  };

  const handleCreateSession = () => {
      if (!newSessionName.trim()) return;
      dispatch({
          type: 'ADD_EXAM_SESSION',
          payload: {
              id: `es${Date.now()}`,
              name: newSessionName, type: newSessionType,
              status: 'open', startDate: new Date().toISOString().split('T')[0]
          }
      });
      setNewSessionName('');
  };

  const handlePublishClassResult = (session: any, published: boolean, reportCount: number) => {
      if (!publishClassId) { alert("Select a class first"); return; }
      if (reportCount === 0) { alert("No marks found."); return; }
      dispatch({
          type: 'PUBLISH_CLASS_RESULT',
          payload: { 
              examSessionId: session.id,
              sessionName: session.name, 
              classId: publishClassId, 
              section: publishSection === '' ? undefined : publishSection, 
              published 
          }
      });
  }

  const selectedClassData = state.systemClasses.find(c => c.name === reviewData.classId);

  if (activeTab === 'issue_notices') {
    return (
        <div className="space-y-8 max-w-4xl">
            <div className="bg-white p-8 rounded-2xl border border-galaxy-100 shadow-lg">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 bg-gold-400 rounded-full flex items-center justify-center text-galaxy-900"><Bell size={20} /></div>
                    <h3 className="text-xl font-bold text-galaxy-900">Issue New Notice</h3>
                </div>
                <form onSubmit={handlePostNotice} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="md:col-span-2"><label className="text-xs font-bold text-gray-400 uppercase">Title</label><input type="text" required className="w-full border p-3 rounded-xl" value={noticeForm.title} onChange={e => setNoticeForm({...noticeForm, title: e.target.value})}/></div>
                        <div><label className="text-xs font-bold text-gray-400 uppercase">Audience</label><select className="w-full border p-3 rounded-xl bg-white" value={noticeForm.audience} onChange={e => setNoticeForm({...noticeForm, audience: e.target.value as any})}><option value="all">Everyone</option><option value="students">Students</option><option value="teachers">Staff</option></select></div>
                    </div>
                    <div><label className="text-xs font-bold text-gray-400 uppercase">Content</label><textarea required rows={6} className="w-full border p-4 rounded-xl" value={noticeForm.content} onChange={e => setNoticeForm({...noticeForm, content: e.target.value})}/></div>
                    <div className="flex justify-end"><button type="submit" className="bg-galaxy-900 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2"><Send size={18} /> Publish</button></div>
                </form>
            </div>
        </div>
    );
  }

  if (activeTab === 'registration' || activeTab === 'users') {
      const usersToManage = state.users
        .filter(u => u.status === 'active' && u.id !== currentUser?.id)
        .filter(u => {
            const matchesSearch = u.name.toLowerCase().includes(searchTerm.toLowerCase()) || u.email.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesRole = filterRole === 'all' || u.role === filterRole;
            return matchesSearch && matchesRole;
        });

      return (
          <div className="space-y-8">
              <div className="bg-white p-6 rounded-xl border border-galaxy-200 shadow-sm">
                  <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><UserCheck className="text-galaxy-600" /> Pending Approvals</h3>
                  {getPendingUsers().length === 0 ? <p className="text-gray-500 italic">No pending requests.</p> : (
                      <div className="grid gap-4">
                          {getPendingUsers().map(u => (
                              <div key={u.id} className="flex items-center justify-between border p-4 rounded-lg bg-yellow-50">
                                  <div><p className="font-bold">{u.name}</p><p className="text-sm">{u.role.toUpperCase()} • {u.email}</p></div>
                                  <div className="flex gap-2"><button onClick={() => handleReject(u.id)} className="px-3 py-1 text-red-600 text-sm">Reject</button><button onClick={() => openReviewModal(u)} className="px-3 py-1 bg-galaxy-600 text-white rounded text-sm flex items-center gap-1"><Eye size={14} /> Review</button></div>
                              </div>
                          ))}
                      </div>
                  )}
              </div>

              {reviewUser && (
                  <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
                      <div className="bg-white rounded-xl shadow-xl max-w-lg w-full overflow-hidden max-h-[90vh] overflow-y-auto">
                          <div className="bg-galaxy-900 text-white p-4 flex justify-between items-center sticky top-0 z-10">
                              <h3 className="font-bold">{reviewUser.status === 'pending' ? 'Review Application' : 'Edit User Details'}</h3>
                              <button onClick={() => setReviewUser(null)}><X size={20} /></button>
                          </div>
                          <div className="p-6 space-y-4">
                              <div className="grid grid-cols-2 gap-4 text-sm">
                                  <div className="col-span-2">
                                      <label className="text-xs font-bold text-gray-500 uppercase">Full Name</label>
                                      <input type="text" value={reviewData.name || ''} onChange={e => setReviewData({...reviewData, name: e.target.value})} className="w-full border p-2 rounded mt-1"/>
                                  </div>
                                  <div className="col-span-2">
                                      <label className="text-xs font-bold text-gray-500 uppercase">Email</label>
                                      <input type="email" value={reviewData.email || ''} onChange={e => setReviewData({...reviewData, email: e.target.value})} className="w-full border p-2 rounded mt-1"/>
                                  </div>
                                  <div className="col-span-2 bg-red-50 p-3 rounded-lg border border-red-100">
                                      <label className="text-xs font-bold text-red-600 uppercase flex items-center gap-1"><Key size={12}/> Reset User Password</label>
                                      <input 
                                          type="text" 
                                          value={reviewData.password || ''} 
                                          onChange={e => setReviewData({...reviewData, password: e.target.value})} 
                                          placeholder="Enter new temporary password"
                                          className="w-full border p-2 rounded mt-1 bg-white"
                                      />
                                      <p className="text-[10px] text-red-400 mt-1">Manual reset for local/demo login fallback.</p>
                                  </div>
                              </div>

                              <div className="flex gap-3 pt-4">
                                  <button onClick={() => setReviewUser(null)} className="flex-1 py-2 border rounded">Cancel</button>
                                  <button onClick={confirmApprovalOrEdit} className="flex-1 py-2 bg-green-600 text-white rounded font-bold">Save Changes</button>
                              </div>
                          </div>
                      </div>
                  </div>
              )}

              <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                  <div className="flex justify-between items-center mb-6">
                      <h3 className="text-xl font-bold">Manage Active Users</h3>
                      <div className="relative w-64">
                          <Search className="absolute left-3 top-2.5 text-gray-400" size={18} />
                          <input type="text" placeholder="Search..." className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}/>
                      </div>
                  </div>
                  <table className="w-full text-left">
                      <thead className="bg-gray-50"><tr><th className="p-3">Name</th><th className="p-3">Role</th><th className="p-3">Actions</th></tr></thead>
                      <tbody className="divide-y">
                        {usersToManage.map(u => (
                            <tr key={u.id} className="hover:bg-gray-50 transition-colors">
                                <td className="p-3 font-medium">{u.name} <br/> <span className="text-xs text-gray-500 font-normal">{u.email}</span></td>
                                <td className="p-3"><span className="px-2 py-1 rounded text-xs font-bold uppercase bg-blue-100 text-blue-700">{u.role}</span></td>
                                <td className="p-3"><button onClick={() => openReviewModal(u)} className="text-galaxy-600 p-2"><Edit2 size={16} /></button></td>
                            </tr>
                        ))}
                      </tbody>
                  </table>
              </div>
          </div>
      );
  }

  return <div>Welcome Admin</div>;
};

export default AdminView;
